const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const end = new Date(now.getFullYear(), now.getMonth(), 0);

function fmt(d) {
  return d.toISOString().slice(0, 10);
}

return [{
  json: {
    ...$json,
    start_date: fmt(start),
    end_date: fmt(end),
    month_label: `${start.getFullYear()}-${String(start.getMonth() + 1).padStart(2, '0')}`
  }
}];

const data = $json.data || [];

let income = 0;
let expenses = 0;
let transfers = 0;

const categories = {};
const merchants = {};
const transactions = [];

for (const group of data) {
  const txs = group.attributes?.transactions || [];

  for (const tx of txs) {
    const amount = Number(tx.amount || 0);
    const type = tx.type || 'unknown';
    const category = tx.category_name || 'Ohne Kategorie';
    const description = tx.description || 'Ohne Beschreibung';
    const destination = tx.destination_name || '';
    const source = tx.source_name || '';

    if (type === 'deposit') income += Math.abs(amount);
    if (type === 'withdrawal') expenses += Math.abs(amount);
    if (type === 'transfer') transfers += Math.abs(amount);

    if (type === 'withdrawal') {
      categories[category] = (categories[category] || 0) + Math.abs(amount);
      const merchant = destination || description;
      merchants[merchant] = (merchants[merchant] || 0) + Math.abs(amount);
    }

    transactions.push({
      date: tx.date,
      type,
      amount,
      description,
      category,
      source,
      destination
    });
  }
}

const top_categories = Object.entries(categories)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([name, amount]) => ({ name, amount: amount.toFixed(2) }));

const top_merchants = Object.entries(merchants)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([name, amount]) => ({ name, amount: amount.toFixed(2) }));

const config = $('Konfiguration').first().json;
const dates = $('Letzten Monat berechnen').first().json;

const summary = {
  month: dates.month_label,
  start_date: dates.start_date,
  end_date: dates.end_date,
  transaction_count: transactions.length,
  income: income.toFixed(2),
  expenses: expenses.toFixed(2),
  transfers: transfers.toFixed(2),
  balance: (income - expenses).toFixed(2),
  top_categories,
  top_merchants,
  transactions
};

const systemPrompt = `Du bist ein Finanzanalyst für private Haushalte.\nAnalysiere Firefly-III-Monatsdaten klar, ehrlich und hilfreich.\nAntworte auf Deutsch.\nKeine erfundenen Zahlen. Nutze nur die gelieferten Daten.`;

const userPrompt = `Analysiere den folgenden Firefly-III-Monat.\n\nGib mir:\n1. Kurzfazit\n2. Einnahmen, Ausgaben und Bilanz\n3. Größte Kostentreiber\n4. Auffällige Buchungen\n5. Sparpotenzial\n6. Konkrete Empfehlungen für den nächsten Monat\n7. Kurze Zusammenfassung als Monatsbericht\n\nDaten:\n${JSON.stringify(summary, null, 2)}`;

return {
  json: {
    firefly_url: config.firefly_url,
    firefly_token: config.firefly_token,
    ...summary,
    systemPrompt,
    userPrompt
  }
};
